// PATCH: Cover retag's canonical transaction tier selection.

func TestLoadRetagTransactionsFiltersHandledRows(t *testing.T) {
	db, err := store.Open(filepath.Join(t.TempDir(), "data.db"))
	if err != nil {
		t.Fatalf("open store: %v", err)
	}
	defer db.Close()

	if _, _, err := db.UpsertBatch("transactions", []json.RawMessage{
		json.RawMessage(`{"id":"101","payee":"Coffee","amount":"10.00","date":"2026-05-01"}`),
		json.RawMessage(`{"id":"102","payee":"Coffee","amount":"10.00","date":"2026-05-01","is_split_parent":true}`),
		json.RawMessage(`{"id":"103","payee":"Coffee","amount":"6.00","date":"2026-05-01","split_parent_id":"102"}`),
		json.RawMessage(`{"id":"104","payee":"Coffee","amount":"4.00","date":"2026-05-01","group_parent_id":"105"}`),
		json.RawMessage(`{"id":"105","payee":"Coffee","amount":"14.00","date":"2026-05-01","is_group_parent":true}`),
	}); err != nil {
		t.Fatalf("UpsertBatch: %v", err)
	}

	txs, err := loadRetagTransactions(context.Background(), db)
	if err != nil {
		t.Fatalf("loadRetagTransactions: %v", err)
	}
	got := map[int]bool{}
	for _, tx := range txs {
		got[tx.ID] = true
	}
	for _, id := range []int{101} {
		if !got[id] {
			t.Fatalf("loaded ids = %v, missing canonical id %d", got, id)
		}
	}
	for _, id := range []int{102, 103, 104, 105} {
		if got[id] {
			t.Fatalf("loaded ids = %v, want handled id %d filtered", got, id)
		}
	}
}

func TestApplyRetagResponseUsesAPIOutcome(t *testing.T) {
	result := applyRetagResponse(retagResult{Errors: []string{}}, json.RawMessage(`{
		"transactions": [{"id": 101}],
		"errors": [{"transaction_index": 1, "errMsg": "category_id does not exist"}]
	}`), 3)

	if result.Updated != 1 {
		t.Fatalf("Updated = %d, want API transaction count 1", result.Updated)
	}
	if len(result.Errors) != 1 || result.Errors[0] != "category_id does not exist" {
		t.Fatalf("Errors = %#v, want API error message", result.Errors)
	}
}

func TestBuildRetagBodyIncludesNotes(t *testing.T) {
	body := buildRetagBody(
		[]retagTransaction{{ID: 101, Tags: []int{1, 2}}},
		true,
		73,
		true,
		[]int{3},
		[]int{1},
		true,
		"shareholder transfer repayment",
	)

	updates, ok := body["transactions"].([]map[string]any)
	if !ok || len(updates) != 1 {
		t.Fatalf("transactions = %#v, want one update", body["transactions"])
	}
	if updates[0]["notes"] != "shareholder transfer repayment" {
		t.Fatalf("notes = %#v, want supplied note", updates[0]["notes"])
	}
	if updates[0]["category_id"] != 73 {
		t.Fatalf("category_id = %#v, want 73", updates[0]["category_id"])
	}
	tags, ok := updates[0]["tags"].([]int)
	if !ok || len(tags) != 2 || tags[0] != 2 || tags[1] != 3 {
		t.Fatalf("tags = %#v, want merged tags [2 3]", updates[0]["tags"])
	}
}

func TestRetagDryRunReportsNotes(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	db, err := store.Open(dbPath)
	if err != nil {
		t.Fatalf("open store: %v", err)
	}
	defer db.Close()

	if _, _, err := db.UpsertBatch("transactions", []json.RawMessage{
		json.RawMessage(`{"id":"101","payee":"ExampleMerchant Wire","amount":"-100.00","date":"2026-05-01"}`),
	}); err != nil {
		t.Fatalf("UpsertBatch: %v", err)
	}

	flags := &rootFlags{asJSON: true, dryRun: true}
	cmd := newTransactionsRetagCmd(flags)
	var out bytes.Buffer
	cmd.SetOut(&out)
	cmd.SetContext(context.Background())
	cmd.SetArgs([]string{
		"--match", "ExampleMerchant",
		"--set-notes", "shareholder transfer repayment",
		"--db", dbPath,
	})

	if err := cmd.Execute(); err != nil {
		t.Fatalf("Execute: %v", err)
	}
	var result retagResult
	if err := json.Unmarshal(out.Bytes(), &result); err != nil {
		t.Fatalf("json output = %q: %v", out.String(), err)
	}
	if result.Matched != 1 {
		t.Fatalf("Matched = %d, want 1", result.Matched)
	}
	if result.NotesApplied == nil || *result.NotesApplied != "shareholder transfer repayment" {
		t.Fatalf("NotesApplied = %#v, want supplied note", result.NotesApplied)
	}
}
